   699	          const entries = Object.entries(item as Record<string, unknown>);
   700	          if (entries.length > 0) {
   701	            const [firstKey, firstVal] = entries[0];
   702	            lines.push(`${prefix}  - ${firstKey}: ${yamlSafeString(firstVal)}`);
   703	            for (let i = 1; i < entries.length; i++) {
   704	              const [k, v] = entries[i];
