import assert from 'node:assert/strict';
import { mkdtempSync, mkdirSync, writeFileSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

const repo = '/workspace/gsd-2';
const prefs = await import(`file://${repo}/src/resources/extensions/gsd/preferences.ts`);

function writePrefs(path, value) {
  writeFileSync(path, `---\nversion: 1\nunique_milestone_ids: ${value}\n---\n`, 'utf8');
}

const tmp = mkdtempSync(join(tmpdir(), 'gsd-prefs-rename-'));
const project = join(tmp, 'project');
const gsd = join(project, '.gsd');
const home = join(tmp, 'home-gsd');
mkdirSync(gsd, { recursive: true });
mkdirSync(home, { recursive: true });

const oldCwd = process.cwd();
const oldHome = process.env.GSD_HOME;
try {
  process.chdir(project);
  process.env.GSD_HOME = home;

  assert.equal(prefs.getProjectGSDPreferencesPath(), join(gsd, 'PREFERENCES.md'), 'project canonical path should be uppercase');
  assert.equal(prefs.getGlobalGSDPreferencesPath(), join(home, 'PREFERENCES.md'), 'global canonical path should be uppercase');

  writePrefs(join(gsd, 'preferences.md'), false);
  writePrefs(join(gsd, 'PREFERENCES.md'), true);
  const projectPrefs = prefs.loadProjectGSDPreferences();
  assert.equal(projectPrefs.path, join(gsd, 'PREFERENCES.md'), 'project loader should prefer uppercase file');
  assert.equal(projectPrefs.preferences.unique_milestone_ids, true, 'project uppercase preferences should win');

  rmSync(join(gsd, 'PREFERENCES.md'));
  const legacyProjectPrefs = prefs.loadProjectGSDPreferences();
  assert.equal(legacyProjectPrefs.path, join(gsd, 'preferences.md'), 'project loader should fall back to lowercase file');
  assert.equal(legacyProjectPrefs.preferences.unique_milestone_ids, false, 'project lowercase fallback should still load');

  writePrefs(join(home, 'preferences.md'), false);
  writePrefs(join(home, 'PREFERENCES.md'), true);
  const globalPrefs = prefs.loadGlobalGSDPreferences();
  assert.equal(globalPrefs.path, join(home, 'PREFERENCES.md'), 'global loader should prefer uppercase file');
  assert.equal(globalPrefs.preferences.unique_milestone_ids, true, 'global uppercase preferences should win');

  console.log('preferences filename migration behavior verified');
} finally {
  process.chdir(oldCwd);
  if (oldHome === undefined) delete process.env.GSD_HOME;
  else process.env.GSD_HOME = oldHome;
  rmSync(tmp, { recursive: true, force: true });
}
