    const response: RemoteQuestionsResponse = {
      config: {
        channel,
        channelId,
        timeoutMinutes,
        pollIntervalSeconds,
      },
      envVarSet,
      tokenSet,
      envVarName,
      status: "configured",
    }
    return Response.json(response, {
