    })
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error)
    return Response.json(
      { error: `Failed to read remote questions config: ${message}` },
      { status: 500, headers: { "Cache-Control": "no-store" } },
    )
  }
}

